var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......이것들은 다 뭐야?","JPN":"……何これ？","ENG":"What are all these?","TWN":"……這些都是什麼啊？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고 로스트 쉽 재난지역인데 왜 출동하는 태스크포스가 하나도 안 보이는 거지?","JPN":"それに、ロストシップ災害地域なのに、どうして担当のタスクフォースが一切見当たらないの？","ENG":"And why isn't there a single TASKFORCE team coming for help in a Lost Ship disaster area?","TWN":"然後明明是失落艦船的受災區，為什麼連一個出動的特遣勢力小隊都沒看到啊？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......그야 지금은 태스크포스 총동원 상황이니까요.","JPN":"……そりゃ、今はタスクフォースが総動員されていますからね。","ENG":"They have no men to spare right now.","TWN":"……那是因為特遣勢力小隊現在都處於總動員的狀況。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이런 경우엔 대도시나 인구밀집지역의 방어가 최우선이 되는 거죠.","JPN":"こういう場合は、大都市や人口密集地の防御が最優先ですから。","ENG":"In a time like this, defending big cities and densely populated areas becomes the top priority.","TWN":"在這種情況下，大城市和人口密集地區才是最優先的防禦目標。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그나마도 힘에 부칠 테니 이런 시골까지 신경 쓸 틈은 없을 겁니다.","JPN":"それすら手に負えない状況で、こんな奥地にまで気が回らないのでしょう。","ENG":"I doubt they'll split forces for a rural area like this.","TWN":"那邊的人手都不太夠了，他們是沒空去管這種鄉下地方的。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"잘 알고 있군.","JPN":"よくわかってるな。","ENG":"Precisely.","TWN":"你真清楚呢。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"덧붙이자면 이런 곳은 원래 우리 같은 무허가나 소규모 용병회사들이 임의로 처리하는 게 일반적이다.","JPN":"ちなみにこういうところは元々、\\n俺たちのような無許可か小規模の軍事企業が任意で片づけるのが一般的だ。","ENG":"And If I may add, it's common in places like this that small-scale or unlicensed mercenary teams handle the problems.","TWN":"順帶一提，通常這種地方，都是由我們這種小規模的傭兵公司任意處理的。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......그나마도 없으면 그대로 방치되는 거고.","JPN":"……それすらなければ、そのまま放置だが。","ENG":"And if there are none to come, they are left unchecked.","TWN":"……如果連我們都不管的話，這些地方就會被放置。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"이봐, 덕분에 쉽게 처리했어.","JPN":"あんたたちのおかげで簡単に始末できたわ。","ENG":"Hey, that was much easier, thanks to you.","TWN":"喂，托你們的福，我們很輕鬆地就處理完了。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"꽤 잘 싸우던데?","JPN":"なかなかの腕だったけど、","ENG":"You've got some skills up your sleeve, huh?","TWN":"你們很能打嘛。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"어디 이름난 태스크포스에서 지원이라도 나온 건가 봐?","JPN":"どこか名のあるタスクフォースから来てくれたの？","ENG":"Are you a cleanup party from a famous TASKFORCE company or something?","TWN":"該不會是哪個有名的特遣勢力來幫忙的吧？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그쪽의 카운터도 대단하더군.","JPN":"そっちのカウンターもなかなかだったよ。","ENG":"The Counter on your side was no less impressive.","TWN":"你們那邊的制裁者也很厲害啊。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"우리가 없었어도 위험할 일은 없었겠어.","JPN":"俺らがいなくても、特段の危機はなかったろう。","ENG":"I assume you didn't need us to take care of it.","TWN":"就算沒有我們，你們看起來也不會有什麼危險。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"뭐...... 카운터는 대단하긴 하지.","JPN":"まあ……カウンターは確かにすごいんだけどね……","ENG":"Yeah... The Counter is impressive.","TWN":"這……制裁者是很厲害沒錯啦。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"카운터는 말이야......","JPN":"カウンターだけはね……","ENG":"As apposed to her mediocre sidekicks...","TWN":"制裁者她啊……"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그보다, 당신이 제시카 그린인가?","JPN":"それより、あんたがジェシカ・グリーンか？","ENG":"By the way, is your name Jessica Green?","TWN":"話說回來，妳是潔西卡．格林嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"내 이름을 어떻게 알고 있는 거지?","JPN":"どうして私の名前を？","ENG":"How do you know my name?","TWN":"你怎麼會知道我的名字？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};